+      $V_{\mathrm{R}}$ (\si{\volt}) & \mc{1}{c}{$\phi_{\mathrm{v}}$ (\si{\degree})} & \mc{1}{c}{$\Delta\phi$ (\si{\degree})} & \mc{1}{c}{$C$ (\si{\pico\farad})} & \mc{1}{c}{$R_{\mathrm{p}}$ (\si{\mega\ohm})} \\
+      \colrule
+      0  & $-175.80$ & 3.87  & 143.07 & 14.52 \\
+      1  & $-168.65$ & 3.28  & 71.98  & 34.00 \\
+      2  & $-167.43$ & 4.50  & 55.68  & 32.08 \\
+      4  & $-166.57$ & 5.36  & 42.53  & 35.20 \\
+      6  & $-166.05$ & 5.88  & 36.36  & 37.51 \\
+      8  & $-165.46$ & 6.47  & 32.76  & 37.81 \\
